css:
@page {
        size: A4;
        margin: 20mm;
    }

    body {
        font-family: Inter, sans-serif;
        font-size: 13px;
        line-height: 1.4;
        color: #222;
        position: relative;
    }

    /* Watermark */
    body::before {
        content: "AI GENERATED REPORT";
        position: fixed;
        top: 40%;
        left: 15%;
        font-size: 60px;
        color: rgba(0, 0, 0, 0.06);
        transform: rotate(-25deg);
        pointer-events: none;
        z-index: -1;
    }

    .section-title {
        font-size: 18px;
        font-weight: 600;
        margin: 0 0 10px 0;
        padding-bottom: 3px;
        border-bottom: 2px solid #000;
    }

    .info-box {
        background: #f4f4f4;
        padding: 10px 14px;
        border-radius: 6px;
        margin-bottom: 20px;
    }

    .question-card {
        border: 1px solid #ddd;
        padding: 12px 14px;
        border-radius: 6px;
        margin-bottom: 10px;
        page-break-inside: avoid;
    }

    .label {
        font-weight: 600;
        margin-bottom: 2px;
    }

    .value {
        margin-bottom: 6px;
        padding-left: 4px;
    }

    .score-box {
        padding: 6px 10px;
        font-weight: 600;
        border-radius: 4px;
        width: fit-content;
        margin-top: 6px;
    }

    .score-green {
        background: #d4edda;
        color: #155724;
        border-left: 4px solid #28a745;
    }

    .score-yellow {
        background: #fff3cd;
        color: #856404;
        border-left: 4px solid #ffc107;
    }

    .score-red {
        background: #f8d7da;
        color: #721c24;
        border-left: 4px solid #dc3545;
    }

    /* Signature Block */
    .signature-block {
        margin-top: 30px;
        page-break-inside: avoid;
    }

    .signature-row {
        display: flex;
        justify-content: space-between;
        margin-top: 40px;
    }

    .sig-box {
        width: 45%;
        text-align: center;
    }

    .sig-line {
        margin-top: 40px;
        border-top: 1px solid #000;
        padding-top: 5px;
        font-size: 13px;
    }

    /* Timestamp */
    .timestamp {
        margin-top: 20px;
        font-size: 12px;
        color: #555;
    }
